    return CatalogEntry(
      catalogId: 'core.$id',
      module: module,
      category: category,
      aliases: aliases,
    );
  }

  final entries = [
    entry(
      id: 'mandelbrot',
      name: 'Mandelbrot',
      dimension: FractalDimension.twoD,
      category: 'Escape-Time',
      aliases: ['classic'],
    ),
    entry(
      id: 'julia',
      name: 'Julia',
      dimension: FractalDimension.twoD,
      category: 'Escape-Time',
    ),
    entry(
      id: 'mandelbulb',
      name: 'Mandelbulb',
      dimension: FractalDimension.threeD,
      category: '3D Fractals',
